-- Ken's Hardened V2 Fix

local b64_0x1l1lI1 = {}
local char_0xllI11I='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xI1lII1=1,#char_0xllI11I do b64_0x1l1lI1[char_0xllI11I:sub(i_0xI1lII1,i_0xI1lII1)] = i_0xI1lII1 - 1 end

function b64_0x1l1lI1.dec_0xI1lII1(d_0xIIII1l)
    d_0xIIII1l = string.gsub(d_0xIIII1l, '[^'..char_0xllI11I..'=]', '')
    local r_0x1II1Il = {}
    for i_0xI1lII1=1, #d_0xIIII1l, 4 do
        local c_0xI1I11l = b64_0x1l1lI1[d_0xIIII1l:sub(i_0xI1lII1,i_0xI1lII1)] or 0
        local c_0xlIllII = b64_0x1l1lI1[d_0xIIII1l:sub(i_0xI1lII1+1,i_0xI1lII1+1)] or 0
        local c_0xI1IIII, c_0xII1l1l = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIIII1l:sub(i_0xI1lII1+2,i_0xI1lII1+2)
        if ch3 == "=" then has3 = false else c_0xI1IIII = b64_0x1l1lI1[ch3] or 0 end
        local ch4 = d_0xIIII1l:sub(i_0xI1lII1+3,i_0xI1lII1+3)
        if ch4 == "=" then has4 = false else c_0xII1l1l = b64_0x1l1lI1[ch4] or 0 end
        local b_0x1IlIIl = c_0xI1I11l * (2^18) + c_0xlIllII * (2^12) + c_0xI1IIII * (2^6) + c_0xII1l1l
        local b_0xIlllll = math.floor(b_0x1IlIIl / (2^16)) % (2^8)
        local b_0x1Il1Il = math.floor(b_0x1IlIIl / (2^8)) % (2^8)
        local b_0x1IIl1I = b_0x1IlIIl % (2^8)
        table.insert(r_0x1II1Il, string.char(b_0xIlllll))
        if has3 then table.insert(r_0x1II1Il, string.char(b_0x1Il1Il)) end
        if has4 then table.insert(r_0x1II1Il, string.char(b_0x1IIl1I)) end
    end
    return table.concat(r_0x1II1Il)
end


local function bxor_0xIlI11l(a_0xlIlIII,b_0xlllllI)
    if bit32 then return bit32.bxor(a_0xlIlIII,b_0xlllllI) end
    local r_0xIIIIll = 0
    for i_0xI1IlIl = 0, 7 do
        local x_0xlll1Il = a_0xlIlIII % 2
        local y_0xI111Il = b_0xlllllI % 2
        if x_0xlll1Il ~= y_0xI111Il then r_0xIIIIll = r_0xIIIIll + (2^i_0xI1IlIl) end
        a_0xlIlIII = math.floor(a_0xlIlIII / 2)
        b_0xlllllI = math.floor(b_0xlllllI / 2)
    end
    return r_0xIIIIll
end


local function bxor_str_0x1lIlI1(s_0xI1IlII, k_0x1Il1ll)
    local r_0xllllII = {}
    for i_0xIllll1=1, #s_0xI1IlII do
        local b_0xIllII1 = string.byte(s_0xI1IlII, i_0xIllll1)
        local kb_0xIl1ll1 = string.byte(k_0x1Il1ll, (i_0xIllll1-1) % #k_0x1Il1ll + 1)
        r_0xllllII[i_0xIllll1] = string.char(bxor_0xIlI11l(b_0xIllII1, kb_0xIl1ll1))
    end
    return table.concat(r_0xllllII)
end


local function getkeys_0xIl1lll()
    local seed = b64_0x1l1lI1.dec_0xI1lII1("QURoYmJaa3I=")
    local k1_enc = b64_0x1l1lI1.dec_0xI1lII1("c3FbFgtpLDE=")
    local k2_enc = b64_0x1l1lI1.dec_0xI1lII1("LAUGDBdjLQo=")
    return bxor_str_0x1lIlI1(k1_enc, seed), bxor_str_0x1lIlI1(k2_enc, seed)
end


local function cff_0xlI1I1l(a_0x1lllIl)
    local st_0xIlIIII = 0
    local res_0xIIIIlI = a_0x1lllIl
    while true do
        if st_0xIlIIII == 0 then
            res_0xIIIIlI = res_0xIIIIlI + 1
            st_0xIlIIII = 1
        elseif st_0xIlIIII == 1 then
            res_0xIIIIlI = res_0xIIIIlI * 2
            st_0xIlIIII = 2
        elseif st_0xIlIIII == 2 then
            res_0xIIIIlI = res_0xIIIIlI - 3
            st_0xIlIIII = 3
        else
            break
        end
    end
    return res_0xIIIIlI
end


local function chain_0x1IlIIl(x) return x*2 end
local function chain_0xlIIIl1(x) return chain_0x1IlIIl(x)+1 end


local d_0xIl1l1l = {
  {op=255, val="", is_enc=true},
}
local pc_0xIlI111 = 1
local stk_0xIII1I1 = {}
stk_0xIII1I1._jmp = nil


local disp_0xl1lllI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIl1lll()

local state_0xllIIII = 0
while true do
    if state_0xllIIII == 0 then  -- FETCH
        if pc_0xIlI111 > #d_0xIl1l1l then break end
        local inst = d_0xIl1l1l[pc_0xIlI111]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0x1l1lI1.dec_0xI1lII1(val)
            d = bxor_str_0x1lIlI1(d, k2)
            val = bxor_str_0x1lIlI1(d, k1)
        end
        stk_0xIII1I1._jmp = nil
        pc_0xIlI111 = pc_0xIlI111 + 1
        cur_op_0xIIlIlI = opcode
        cur_val_0xIIlIlI = val
        state_0xllIIII = 1

    elseif state_0xllIIII == 1 then  -- EXECUTE
        local handler = disp_0xl1lllI[cur_op_0xIIlIlI]
        if handler then
            handler(stk_0xIII1I1, cur_val_0xIIlIlI)
        end
        if stk_0xIII1I1._jmp then
            pc_0xIlI111 = pc_0xIlI111 + stk_0xIII1I1._jmp
        end
        state_0xllIIII = 0
